# app/mailers/application_mailer.rb
class ApplicationMailer < ActionMailer::Base
  default from: ENV['SENDGRID_FROM_EMAIL'] || 'noreply@example.com'
  layout 'mailer'
end

# app/mailers/user_mailer.rb
class UserMailer < ApplicationMailer
  def welcome_email(user)
    @user = user
    @url = root_url
    
    mail(
      to: email_address_with_name(@user.email, @user.name),
      subject: 'Welcome to Our Application',
      reply_to: ENV['SENDGRID_REPLY_TO_EMAIL']
    )
  end

  def notification_email(user, subject, message)
    @user = user
    @message = message
    
    mail(
      to: @user.email,
      subject: subject,
      template_name: 'notification'
    )
  end

  def password_reset(user, reset_token)
    @user = user
    @reset_token = reset_token
    @reset_url = password_reset_url(token: @reset_token)
    
    mail(
      to: @user.email,
      subject: 'Password Reset Instructions'
    )
  end

  def bulk_email(users, subject, message)
    @message = message
    
    users.each do |user|
      @user = user
      mail(
        to: user.email,
        subject: subject,
        template_name: 'bulk_notification'
      ).deliver_later
    end
  end

  def email_with_attachment(user, subject, attachment_path)
    @user = user
    
    attachments[File.basename(attachment_path)] = File.read(attachment_path) if File.exist?(attachment_path)
    
    mail(
      to: @user.email,
      subject: subject
    )
  end

  def custom_headers_email(user)
    @user = user
    
    headers['X-Custom-Header'] = 'CustomValue'
    headers['X-Priority'] = '1'
    
    mail(
      to: @user.email,
      subject: 'Email with Custom Headers',
      cc: ENV['SENDGRID_CC_EMAIL'],
      bcc: ENV['SENDGRID_BCC_EMAIL']
    )
  end
end

